sys_script_client.script:
// Copyrights belong to Discover Technologies LLC. © 2019 Discover Technologies LLC
// Script Continued Below
function onChange(control, oldValue, newValue, isLoading, isTemplate) {
// STRY0076609 removed the condition to stop when loading.  Even set when loading
if(newValue == 'true'){
	var msg = 'This Task is dependent on the completion of its Subtasks and it will not be marked as Unassigned or Assigned until all Subtasks have been Completed, Canceled, or Closed Incomplete.';

	// call back to server to see if this task and the child task are both approval types
	var ajax  = new GlideAjax('ClientTaskTemplateHelpers');
	ajax.addParam('sysparm_name', 'checkForApprovalTypeOnTaskTempAndSubTaskTemp');
	ajax.addParam('taskTempId', g_form.getUniqueValue());
	ajax.getXML(function(response){
		try{
			var data = response.responseXML.documentElement.getAttribute("answer");
			if(data == 'true'){
				msg = msg + 'This Task is an "Approval" Task Type and it has a Subtask with an "Approval" Task Type. If the Subtask is Rejected, then this task will be rejected. Uncheck to break the dependency.';
			}
			g_form.showFieldMsg('u_wait_for_subtasks_to_finish', msg,'info');
		}catch(e){
			jslog (e);
		}
	});

} else if (!isLoading && newValue == 'false'){
	g_form.showFieldMsg('u_wait_for_subtasks_to_finish', 'This Task is no longer dependent on the completion of its Subtasks.','info');
}

}
